entity user { name; id: integer; value1: integer; value2: integer; }
function fi(x: integer, tag: text): integer { print(tag); return x; }
query q(a: integer) = user @* {} ( 
            when {
                fi(a, 'A1') == fi(25, 'C1') -> fi(501, 'R1');
                fi(a, 'A2') < .value1 -> fi(502, 'R2');
                fi(a, 'A3') == fi(133, 'C3') -> fi(503, 'R3');
                fi(a, 'A4') > .value2 -> fi(504, 'R4');
                else -> fi(505, 'R5')
            }
         );
